/*
* Replace default "No Data Available" message in Location dropdown
*
* @param none
* @return none
*
* by Adriana Centellas
*/

$(document).on('click', '[custom-css-selector="CQP_LOCATION_CSS"]', function () {

    setTimeout(function () {

        const option = $('[custom-css-selector="CQP_LOCATION_CSS"] .multiselect__option:contains("No Data Available")');

        if (option.length) {
            option.text('No locations registered for the selected country. Please contact an administrator.');
        }

    }, 50);

});

var required = this._parent.REQUIRED_IF;
var country = this._parent.CQP_COUNTRY;

if(required == true && country == "PANAMÁ"){
    return true;
}

return false;

/*
* By Diego Tapia
*/
let FIND_COORDS = this.FIND_COORDS
let CQP_COUNTRY = this._parent.CQP_COUNTRY
let CQP_COUNTRY_SEARCH = this._parent._parent.CQP_COUNTRY_SEARCH

if (CQP_COUNTRY_SEARCH != undefined && CQP_COUNTRY_SEARCH != null) {
    return CQP_COUNTRY_SEARCH[CQP_COUNTRY_SEARCH.map((country) => country.data.COUNTRY).indexOf(CQP_COUNTRY)].data.COUNTRY_CODE;
}

return ""
